<script setup lang="ts">
import {computed,onMounted,reactive,ref} from 'vue';import {api,type Envelope} from '@/api';import {ElMessage,ElMessageBox} from 'element-plus';import {useAuthStore} from '@/stores/auth';
const auth=useAuthStore(),canWrite=computed(()=>auth.can('employee:write')),canMaster=computed(()=>auth.can('master:manage'));const rows=ref<any[]>([]),total=ref(0),page=ref(1),keyword=ref(''),dialog=ref(false),importing=ref(false),batches=ref<any[]>([]),stations=ref<any[]>([]),mentors=ref<any[]>([]);const form=reactive<any>({employeeNo:'',name:'',batchId:null,stationId:null,mentorUserId:null,school:'',major:'',education:'',birthDate:null,nativePlace:'',residence:'',phone:'',onboardDate:null});
async function load(){const r=await api.get<any,Envelope<any>>('/employees',{params:{page:page.value,size:20,keyword:keyword.value}});rows.value=r.data.records;total.value=r.data.total}async function masters(){const [b,s,m]=await Promise.all([api.get<any,Envelope<any[]>>('/batches'),api.get<any,Envelope<any[]>>('/stations'),api.get<any,Envelope<any[]>>('/mentors')]);batches.value=b.data;stations.value=s.data;mentors.value=m.data}async function save(){await api.post('/employees',form);ElMessage.success('员工已创建');dialog.value=false;load()}async function upload(o:any){importing.value=true;try{const fd=new FormData();fd.append('file',o.file);const r=await api.post<any,Envelope<any>>('/imports/employees',fd);r.data.errors.length?ElMessage.error(`第${r.data.errors[0].row}行：${r.data.errors[0].message}`):ElMessage.success(`已导入 ${r.data.imported} 人`);load()}finally{importing.value=false}}async function template(){const blob=await api.get<any,Blob>('/imports/employees/template',{responseType:'blob'});download(blob,'新员工导入模板.xlsx')}function download(blob:Blob,name:string){const u=URL.createObjectURL(blob),a=document.createElement('a');a.href=u;a.download=name;a.click();URL.revokeObjectURL(u)}async function addMaster(type:'batches'|'stations'){const {value}=await ElMessageBox.prompt('请输入名称',type==='batches'?'新增批次':'新增服务站');await api.post('/'+type,{name:value});masters()}onMounted(()=>{load();masters()});
</script>
<template><div class="page"><div class="page-head"><h2>人员台账</h2><el-button v-if="canWrite" type="primary" @click="dialog=true">新增员工</el-button></div><div class="toolbar"><el-input v-model="keyword" placeholder="姓名或工号" style="width:220px" @keyup.enter="load"/><el-button @click="load">查询</el-button><el-button v-if="canMaster" @click="addMaster('batches')">新增批次</el-button><el-button v-if="canMaster" @click="addMaster('stations')">新增服务站</el-button><el-button v-if="canWrite" @click="template">导入模板</el-button><el-upload v-if="canWrite" :show-file-list="false" :http-request="upload" accept=".xlsx"><el-button :loading="importing">导入 Excel</el-button></el-upload></div><el-table :data="rows" stripe><el-table-column prop="employee_no" label="工号"/><el-table-column prop="name" label="姓名"/><el-table-column prop="batch_name" label="批次"/><el-table-column prop="station_name" label="服务站"/><el-table-column prop="mentor_name" label="导师"/><el-table-column prop="school" label="毕业学校"/><el-table-column prop="major" label="专业"/><el-table-column prop="education" label="学历"/></el-table><el-pagination v-model:current-page="page" :total="total" :page-size="20" @change="load"/><el-dialog v-model="dialog" title="新增员工" width="720px"><el-form label-position="top"><div class="form-grid"><el-form-item label="工号"><el-input v-model="form.employeeNo"/></el-form-item><el-form-item label="姓名"><el-input v-model="form.name"/></el-form-item><el-form-item label="批次"><el-select v-model="form.batchId"><el-option v-for="x in batches" :key="x.id" :label="x.name" :value="x.id"/></el-select></el-form-item><el-form-item label="服务站"><el-select v-model="form.stationId"><el-option v-for="x in stations" :key="x.id" :label="x.name" :value="x.id"/></el-select></el-form-item><el-form-item label="导师"><el-select v-model="form.mentorUserId"><el-option v-for="x in mentors" :key="x.id" :label="x.display_name" :value="x.id"/></el-select></el-form-item><el-form-item label="学校"><el-input v-model="form.school"/></el-form-item><el-form-item label="专业"><el-input v-model="form.major"/></el-form-item><el-form-item label="学历"><el-input v-model="form.education"/></el-form-item><el-form-item label="手机号"><el-input v-model="form.phone"/></el-form-item></div></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
